**Vulnerability: Staking Time Reset on Additional Deposits**

When a user calls `stake()` again to add more tokens, `stakeTime[msg.sender]` is reset to `block.timestamp`, erasing the accrued reward time on their *existing* stake. A user who staked 100 tokens for 30 days and then adds 1 more token loses all 30 days of accrued rewards on their original stake.

This is a logical error that silently destroys user funds.

**Fix**: calculate and checkpoint pending rewards *before* updating the stake:
```solidity
mapping(address => uint256) public pendingRewards;

function _checkpoint(address user) internal {
    uint256 elapsed = block.timestamp - stakeTime[user];
    pendingRewards[user] += staked[user] * RATE * elapsed;
    stakeTime[user] = block.timestamp;
}

function stake(uint256 amount) external {
    _checkpoint(msg.sender);
    staked[msg.sender] += amount;
    token.safeTransferFrom(msg.sender, address(this), amount);
}

function claim() external {
    _checkpoint(msg.sender);
    uint256 reward = pendingRewards[msg.sender];
    pendingRewards[msg.sender] = 0;
    rewardToken.safeTransfer(msg.sender, reward);
}
